mage card backs are only\r\n-- used to identify decks that are using a different crit order.\r\n--DamageCardBack = \u0027https://steamusercontent-a.akamaihd.net/ugc/919176040734153013/698D86D59D895E81014C563124F02588FC9C7F41/\u0027\r\n\r\n-- The backs of the faction damage decks.\r\nREB_DamageCardBack =\r\n\u0027https://steamusercontent-a.akamaihd.net/ugc/1021700505297731217/E90648B79A41C9422866EAEEB61091E8AAC18A17/\u0027\r\nIMP_DamageCardBack =\r\n\u0027https://steamusercontent-a.akamaihd.net/ugc/1021700308760157467/0FCF207040A77E7CD02D83A543F4968499F530D4/\u0027\r\nSCUM_DamageCardBack =\r\n\u0027https://steamusercontent-a.akamaihd.net/ugc/1021700505297740500/413E9084E880E86ABE297C05D05F56E5BA01BAF6/\u0027\r\nRIS_DamageCardBack =\r\n\u0027https://steamusercontent-a.akamaihd.net/ugc/1021700308760233507/8DC53DF987FDD4A47FA25ABF8E55FED045557FD6/\u0027\r\nFO_DamageCardBack =\r\n\u0027https://steamusercontent-a.akamaihd.net/ugc/1021700505297719267/01067DDCA8602EF038050E79573A15408F04B9FA/\u0027\r\nGRP_DamageCardBack =\r\n\u0027https://steamusercontent-a.akamaihd.net/ugc/1021700308760057332/D053AF6145BAAE2AE39E04D205128D6A7A4FEC03/\u0027\r\nCIS_DamageCardBack =\r\n\u0027https://steamusercontent-a.akamaihd.net/ugc/1021700308759725288/38037546D88D2CD0E2B91FB5EE6261CC83E00136/\u0027\r\n\r\n-- The indexed crit names used to name the tokens and adjust the image.\r\nCritNames =\r\n{\r\n    [\u002700\u0027] = \u0027CriticalHit\u0027, -- Panicked Pilot\r\n    [\u002701\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002702\u0027] = \u0027BlindedPilot\u0027,\r\n    [\u002703\u0027] = \u0027BlindedPilot\u0027,\r\n    [\u002704\u0027] = \u0027WoundedPilot\u0027,\r\n    [\u002705\u0027] = \u0027WoundedPilot\u0027,\r\n    [\u002706\u0027] = \u0027StunnedPilot\u0027,\r\n    [\u002707\u0027] = \u0027StunnedPilot\u0027,\r\n    [\u002708\u0027] = \u0027ConsoleFire\u0027,\r\n    [\u002709\u0027] = \u0027ConsoleFire\u0027,\r\n    [\u002710\u0027] = \u0027DamagedEngine\u0027,\r\n    [\u002711\u0027] = \u0027DamagedEngine\u0027,\r\n    [\u002712\u0027] = \u0027WeaponsFailure\u0027,\r\n    [\u002713\u0027] = \u0027WeaponsFailure\u0027,\r\n    [\u002714\u0027] = \u0027HullBreach\u0027,\r\n    [\u002715\u0027] = \u0027HullBreach\u0027,\r\n    [\u002716\u0027] = \u0027StructuralDamage\u0027,\r\n    [\u002717\u0027] = \u0027StructuralDamage\u0027,\r\n    [\u002718\u0027] = \u0027DamagedSensorArray\u0027,\r\n    [\u002719\u0027] = \u0027DamagedSensorArray\u0027,\r\n    [\u002720\u0027] = \u0027LooseStabilizer\u0027,\r\n    [\u002721\u0027] = \u0027LooseStabilizer\u0027,\r\n    [\u002722\u0027] = \u0027DisabledPowerRegulator\u0027,\r\n    [\u002723\u0027] = \u0027DisabledPowerRegulator\u0027,\r\n    [\u002724\u0027] = \u0027FuelLeak\u0027,\r\n    [\u002725\u0027] = \u0027FuelLeak\u0027,\r\n    [\u002726\u0027] = \u0027FuelLeak\u0027,\r\n    [\u002727\u0027] = \u0027FuelLeak\u0027,\r\n    [\u002728\u0027] = \u0027CriticalHit\u0027, -- Direct Hit\r\n    [\u002729\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002730\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002731\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002732\u0027] = \u0027CriticalHit\u0027,\r\n}\r\n\r\nAltCritNames =\r\n{\r\n    [\u002700\u0027] = \u0027BlindedPilot\u0027,\r\n    [\u002701\u0027] = \u0027BlindedPilot\u0027,\r\n    [\u002702\u0027] = \u0027ConsoleFire\u0027,\r\n    [\u002703\u0027] = \u0027ConsoleFire\u0027,\r\n    [\u002704\u0027] = \u0027DamagedEngine\u0027,\r\n    [\u002705\u0027] = \u0027DamagedEngine\u0027,\r\n    [\u002706\u0027] = \u0027DamagedSensorArray\u0027,\r\n    [\u002707\u0027] = \u0027DamagedSensorArray\u0027,\r\n    [\u002708\u0027] = \u0027CriticalHit\u0027, -- Direct Hit\r\n    [\u002709\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002710\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002711\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002712\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002713\u0027] = \u0027DisabledPowerRegulator\u0027,\r\n    [\u002714\u0027] = \u0027DisabledPowerRegulator\u0027,\r\n    [\u002715\u0027] = \u0027FuelLeak\u0027,\r\n    [\u002716\u0027] = \u0027FuelLeak\u0027,\r\n    [\u002717\u0027] = \u0027FuelLeak\u0027,\r\n    [\u002718\u0027] = \u0027FuelLeak\u0027,\r\n    [\u002719\u0027] = \u0027HullBreach\u0027,\r\n    [\u002720\u0027] = \u0027HullBreach\u0027,\r\n    [\u002721\u0027] = \u0027LooseStabilizer\u0027,\r\n    [\u002722\u0027] = \u0027LooseStabilizer\u0027,\r\n    [\u002723\u0027] = \u0027CriticalHit\u0027, -- Panicked Pilot\r\n    [\u002724\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002725\u0027] = \u0027StructuralDamage\u0027,\r\n    [\u002726\u0027] = \u0027StructuralDamage\u0027,\r\n    [\u002727\u0027] = \u0027StunnedPilot\u0027,\r\n    [\u002728\u0027] = \u0027StunnedPilot\u0027,\r\n    [\u002729\u0027] = \u0027WeaponsFailure\u0027,\r\n    [\u002730\u0027] = \u0027WeaponsFailure\u0027,\r\n    [\u002731\u0027] = \u0027WoundedPilot\u0027,\r\n    [\u002732\u0027] = \u0027WoundedPilot\u0027,\r\n}\r\n\r\nAltCritNamesCIS =\r\n{\r\n    [\u002700\u0027] = \u0027CriticalHit\u0027, -- Panicked Pilot\r\n    [\u002701\u0027] = \u0027CriticalHit\u0027, -- Direct Hit\r\n    [\u002702\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002703\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002704\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002705\u0027] = \u0027CriticalHit\u0027,\r\n    [\u002706\u0027] = \u0027FuelLeak\u0027,\r\n    [\u002707\u0027] = \u0027FuelLeak\u0027,\r\n    [\u002708\u0027] = \u0027FuelLeak\u0027,\r\n    [\u002709\u0027] = \u0027FuelLeak\u0027,\r\n    [\u002710\u0027] = \u0027DisabledPowerRegulator\u0027,\r\n    [\u002711\u0027] = \u0027DisabledPowerRegulator\u0027,\r\n    [\u002712\u0027] = \u0027LooseStabilizer\u0027,\r\n    [\u002713\u0027] = \u0027LooseStabilizer\u0027,\r\n    [\u002714\u0027] = \u0027DamagedSensorArray\u0027,\r\n    [\u002715\u0027] = \u0027DamagedSensorArray\u0027,\r\n    [\u002716\u0027] = \u0027StructuralDamage\u0027,\r\n    [\u002717\u0027] = \u0027StructuralDamage\u0027,\r\n    [\u002718\u0027] = \u0027HullBreach\u0027,\r\n    [\u002719\u0027] = \u0027HullBreach\u0027,\r\n    [\u002720\u0027] = \u0027WeaponsFailure\u0027,\r\n    [\u002721\u0027] = \u0027WeaponsFailure\u0027,\r\n    [\u002722\u0027] = \u0027DamagedEngine\u0027,\r\n    [\u002723\u0027] = \u0027DamagedEngine\u0027,\r\n    [\u002724\u0027] = \u0027ConsoleFire\u0027,\r\n    [\u002725\u0027] = \u0027ConsoleFire\u0027,\r\n    [\u002726\u0027] = \u0027StunnedPilot\u0027,\r\n    [\u002727\u0027] = \u0027StunnedPilot\u0027,\r\n    [\u002728\u0027] = \u0027WoundedPilot\u0027,\r\n    [\u002729\u0027] = \u0027WoundedPilot\u0027,\r\n    [\u002730\u0027] = \u0027BlindedPilot\u0027,\r\n    [\u002731\u0027] = \u0027BlindedPilot\u0027,\r\n    [\u002732\u0027] = \u0027CriticalHit\u0027, -- Panicked Pilot\r\n}\r\n\r\n-- Variable to prevent it from updating multiple times on a collision.\r\nsetToken = false\r\n\r\n-- Variable to check if this is one of the crit tokens.\r\nIsCritToken = true\r\n\r\nfunction onPickUp(color)\r\n    setToken = true\r\nend\r\n\r\n-- When this collides with a damage card, check what card it is and\r\n-- update the image and name.\r\nfunction onCollisionEnter(collisionInfo)\r\n    if setToken then\r\n        local obj = collisionInfo.collision_object\r\n\r\n        local critNameTable = CritNames\r\n\r\n        local objData = obj.getCustomObject()\r\n        if objData.back ~= nil and obj.is_face_down == false then\r\n            -- If this is Crazy Vulcan\u0027s faction damage decks, they use a different card order\r\n            -- then the crit order so we are using different tables for those decks.\r\n            if objData.back == REB_DamageCardBack or objData.back == IMP_DamageCardBack or\r\n                objData.back == SCUM_DamageCardBack or objData.back == RIS_DamageCardBack or\r\n                objData.back == FO_DamageCardBack or objData.back == GRP_DamageCardBack then\r\n                critNameTable = AltCritNames\r\n            elseif objData.back == CIS_DamageCardBack then\r\n                critNameTable = AltCritNamesCIS\r\n            end\r\n\r\n            local cardId = getCardID(obj)\r\n\r\n            if cardId ~= nil then\r\n                local critName = critNameTable[string.sub(cardId, -2)]\r\n\r\n                if critName ~= nil then\r\n                    -- Set token name\r\n                    self.setName(splitCamel(critName))\r\n\r\n                    -- Set token image\r\n                    local customTable = self.getCustomObject()\r\n                    customTable.diffuse = Images[critName]\r\n                    self.setCustomObject(customTable)\r\n                    self.reload()\r\n\r\n                    setToken = false\r\n                end\r\n            end\r\n        end\r\n    end\r\nend\r\n\r\n-- Convert the camelcase name to a multi-word name.\r\nfunction splitCamel(s)\r\n    local function split(char)\r\n        return \u0022 \u0022 .. char\r\n    end\r\n\r\n    return (s:gsub(\u0022[A-Z]\u0022, split):gsub(\u0022^.\u0022, string.upper))\r\nend\r\n\r\n-- Get the card\u0027s ID to figure out which crit it is.\r\nfunction getCardID(card)\r\n    local cardData = JSON.decode(card.getJSON())\r\n    return cardData[\u0027CardID\u0027]\r\nend\r\n\r\n-- Debug function to display the values of a table into the chat.\r\nfunction displayTable(arg)\r\n    output = \u0022\u0022\r\n    for key, value in pairs(arg) do\r\n        output = output .. \u0022\\n\u0022 .. key .. \u0022: \u0022;\r\n        if type(value) == \u0022table\u0022 then\r\n            output = output .. displayTable(value)\r\n        elseif type(value) == \u0027boolean\u0027 then\r\n            if value then\r\n                output = output .. \u0022true\u0022\r\n            else\r\n                output = output .. \u0022false\u0022\r\n            end\r\n        else\r\n            output = output .. value\r\n        end\r\n    end\r\n\r\n    return output\r\nend\r\n\nend)\nreturn __bundle_require(\u0022Critical Hit.4445ff.lua\u0022)